  9	const ALLOWED_TECH_DESIGN_COMPANIONS = [
 10	  "tech-design-cli-runtime.md",
 11	  "tech-design-skill-process.md",
 12	] as const;
 13	
 14	async function pathIsDirectory(path: string): Promise<boolean> {
 15	  try {
 16	    return (await stat(path)).isDirectory();
 17	  } catch {
 18	    return false;
 19	  }
 20	}
