 65	export async function inspectSpecPack(specPackRoot: string): Promise<InspectResult> {
 66	  const resolvedRoot = resolve(specPackRoot);
 67	  const epicPath = join(resolvedRoot, "epic.md");
 68	  const techDesignPath = join(resolvedRoot, "tech-design.md");
 69	  const testPlanPath = join(resolvedRoot, "test-plan.md");
 70	  const storiesDir = join(resolvedRoot, "stories");
 71	  const storiesFile = join(resolvedRoot, "stories.md");
 72	  const blockers: string[] = [];
 73	  const notes: string[] = [];
 74	
 75	  const repoRoot = await resolveGitRepoRoot(resolvedRoot);
 76	  if (!repoRoot) {
 77	    blockers.push(`Spec-pack root is not inside a git repo: ${resolvedRoot}`);
 78	  }
 79	
 80	  if (!(await pathExists(epicPath))) {
 81	    blockers.push("Missing required artifact: epic.md");
 82	  }
 83	
 84	  if (!(await pathExists(techDesignPath))) {
 85	    blockers.push("Missing required artifact: tech-design.md");
 86	  }
 87	
 88	  if (!(await pathExists(testPlanPath))) {
 89	    blockers.push("Missing required artifact: test-plan.md");
 90	  }
 91	
 92	  const storiesDirExists = await pathIsDirectory(storiesDir);
 93	  if (!storiesDirExists && (await pathExists(storiesFile))) {
 94	    blockers.push("Expected stories/ directory but found stories.md");
 95	  } else if (!storiesDirExists) {
 96	    blockers.push("Missing required artifact: stories/");
 97	  }
 98	
 99	  const rootEntries = await readdir(resolvedRoot);
100	  const techDesignArtifacts = resolveTechDesignArtifacts(rootEntries);
101	  blockers.push(...techDesignArtifacts.blockers);
102	
103	  const storyOrder = storiesDirExists
104	    ? await resolveStoryOrder(storiesDir)
105	    : { status: "ready" as const, stories: [], notes: [] };
106	  notes.push(...storyOrder.notes);
107	  const implInsertPath = join(
108	    resolvedRoot,
109	    "custom-story-impl-prompt-insert.md"
110	  );
111	  const verifierInsertPath = join(
112	    resolvedRoot,
113	    "custom-story-verifier-prompt-insert.md"
114	  );
115	  const implInsertExists = await pathExists(implInsertPath);
116	  const verifierInsertExists = await pathExists(verifierInsertPath);
117	
118	  if (implInsertExists && !(await pathReadable(implInsertPath))) {
119	    blockers.push(
120	      "Unreadable prompt insert: custom-story-impl-prompt-insert.md"
121	    );
122	  }
123	
124	  if (verifierInsertExists && !(await pathReadable(verifierInsertPath))) {
125	    blockers.push(
126	      "Unreadable prompt insert: custom-story-verifier-prompt-insert.md"
127	    );
128	  }
129	
130	  const status =
131	    blockers.length > 0
132	      ? "blocked"
133	      : storyOrder.status === "needs-user-decision"
134	        ? "needs-user-decision"
135	        : "ready";
136	
137	  const result: InspectResult = {
138	    status,
139	    specPackRoot: resolvedRoot,
140	    techDesignShape: techDesignArtifacts.techDesignShape,
141	    artifacts: {
142	      epicPath,
143	      techDesignPath,
144	      techDesignCompanionPaths: techDesignArtifacts.companionPaths.map((file) =>
145	        join(resolvedRoot, file)
146	      ),
147	      testPlanPath,
148	      storiesDir,
149	    },
150	    stories: storyOrder.stories,
151	    inserts: {
152	      customStoryImplPromptInsert: implInsertExists ? "present" : "absent",
153	      customStoryVerifierPromptInsert: verifierInsertExists
154	        ? "present"
155	        : "absent",
156	    },
157	    blockers,
158	    notes,
159	  };
160	
161	  return inspectResultSchema.parse(result);
162	}

 1	import { readdir } from "node:fs/promises";
 2	import { basename, join } from "node:path";
 3	
 4	import { readTextFile } from "./fs-utils";
 5	
 6	interface StoryRecord {
 7	  id: string;
 8	  title: string;
 9	  path: string;
10	  order: number;
11	}
12	
13	interface StoryOrderResolution {
14	  status: "ready" | "needs-user-decision";
15	  stories: StoryRecord[];
16	  notes: string[];
17	}
18	
19	function extractStoryTitle(content: string, fallback: string): string {
20	  const match = content.match(/^#\s+(.+)$/m);
21	  return match?.[1]?.trim() || fallback;
22	}
23	
24	function numericPrefix(fileName: string): number | null {
25	  const match = fileName.match(/^(\d+)-/);
26	  return match ? Number(match[1]) : null;
27	}
28	
29	export async function resolveStoryOrder(
30	  storiesDir: string
31	): Promise<StoryOrderResolution> {
32	  const entries = await readdir(storiesDir, { withFileTypes: true });
33	  const fileNames = entries
34	    .filter((entry) => entry.isFile() && entry.name.endsWith(".md"))
35	    .map((entry) => entry.name)
36	    .filter((fileName) => fileName !== "coverage.md");
37	  const numericFileNames = fileNames.filter(
38	    (fileName) => numericPrefix(fileName) !== null
39	  );
40	  const nonNumericFileNames = fileNames.filter(
41	    (fileName) => numericPrefix(fileName) === null
42	  );
43	
44	  if (numericFileNames.length > 0 && nonNumericFileNames.length > 0) {
45	    return {
46	      status: "needs-user-decision",
47	      stories: [],
48	      notes: [
49	        "Mixed numeric and non-numeric story filenames require an explicit user ordering decision.",
50	      ],
51	    };
52	  }
53	
54	  const notes: string[] = [];
55	  const orderedFileNames =
56	    numericFileNames.length === 0
57	      ? [...fileNames].sort((left, right) => left.localeCompare(right))
58	      : [...fileNames].sort((left, right) => {
59	          const leftPrefix = numericPrefix(left) ?? Number.MAX_SAFE_INTEGER;
60	          const rightPrefix = numericPrefix(right) ?? Number.MAX_SAFE_INTEGER;
61	          if (leftPrefix !== rightPrefix) {
62	            return leftPrefix - rightPrefix;
63	          }
64	          return left.localeCompare(right);
65	        });
66	
67	  if (numericFileNames.length === 0 && fileNames.length > 0) {
68	    notes.push(
69	      "Story filenames do not use numeric prefixes; lexical ordering was applied."
70	    );
71	  }
72	
73	  const stories: StoryRecord[] = [];
74	  for (const [index, fileName] of orderedFileNames.entries()) {
75	    const path = join(storiesDir, fileName);
76	    const content = await readTextFile(path);
77	    stories.push({
78	      id: basename(fileName, ".md"),
79	      title: extractStoryTitle(content, basename(fileName, ".md")),
80	      path,
81	      order: index + 1,
82	    });
83	  }
84	
85	  return {
86	    status: "ready",
87	    stories,
88	    notes,
89	  };
90	}

