123	async function ciCandidates(specPackRoot: string): Promise<GateSourceCandidates[]> {
124	  const workflowsDir = join(specPackRoot, ".github", "workflows");
125	  if (!(await pathExists(workflowsDir))) {
126	    return [];
127	  }
128	
129	  const entries = await readdir(workflowsDir, { withFileTypes: true });
130	  const candidates: GateSourceCandidates = {
131	    story: [],
132	    epic: [],
133	    source: "CI configuration",
134	  };
135	
136	  for (const entry of entries) {
137	    if (!entry.isFile() || !entry.name.match(/\.ya?ml$/)) {
138	      continue;
139	    }
140	
141	    const content = await readTextFile(join(workflowsDir, entry.name));
142	    for (const match of content.matchAll(/run:\s*(.+)$/gim)) {
143	      const command = match[1].trim();
144	      if (command.includes("green-verify")) {
145	        candidates.story.push(command);
146	      }
147	      if (command.includes("verify-all")) {
148	        candidates.epic.push(command);
149	      }
150	    }
151	  }
152	
153	  if (candidates.story.length === 0 && candidates.epic.length === 0) {
154	    return [];
155	  }
156	
157	  return [candidates];
158	}
