 17	async function runCommand(params: {
 18	  file: string;
 19	  args: string[];
 20	  cwd: string;
 21	  env?: Record<string, string | undefined>;
 22	  timeoutMs: number;
 23	}) {
 24	  try {
 25	    const result = await execFileAsync(params.file, params.args, {
 26	      cwd: params.cwd,
 27	      env: {
 28	        ...process.env,
 29	        ...params.env,
 30	      },
 31	      timeout: params.timeoutMs,
 32	    });
 33	    return {
 34	      success: true as const,
 35	      stdout: redactSensitiveText(result.stdout.trim()),
 36	      stderr: redactSensitiveText(result.stderr.trim()),
 37	    };
 38	  } catch (error) {
 39	    const failed = error as {
 40	      stdout?: string;
 41	      stderr?: string;
 42	      code?: string | number;
 43	      message?: string;
 44	      killed?: boolean;
 45	      signal?: string;
 46	    };
 47	    return {
 48	      success: false as const,
 49	      stdout: redactSensitiveText(failed.stdout?.trim() ?? ""),
 50	      stderr: redactSensitiveText(
 51	        failed.stderr?.trim() ?? failed.message ?? String(error)
 52	      ),
 53	      code: failed.code,
 54	      timedOut: failed.signal === "SIGTERM" || failed.killed === true,
 55	    };
 56	  }
 57	}
