 59	function executableForHarness(harness: "claude-code" | SecondaryHarness): string | null {
 60	  switch (harness) {
 61	    case "claude-code":
 62	      return "claude";
 63	    case "codex":
 64	      return "codex";
 65	    case "copilot":
 66	      return "copilot";
 67	    case "none":
 68	      return null;
 69	  }
 70	}
 71	
 72	function failureNotes(result: {
 73	  stderr: string;
 74	  timedOut?: boolean;
 75	  code?: string | number;
 76	}, executable: string, step: string): string[] {
 77	  if (result.stderr) {
 78	    return [result.stderr];
 79	  }
 80	
 81	  if (result.timedOut) {
 82	    return [`${executable} ${step} timed out`];
 83	  }
 84	
 85	  return [`Unable to execute ${executable} ${step}`];
 86	}
