 33	function renderHumanSummary(envelope: OutputEnvelope) {
 34	  if (
 35	    typeof envelope.result !== "object" ||
 36	    envelope.result === null ||
 37	    !("providerMatrix" in envelope.result)
 38	  ) {
 39	    return `preflight: ${envelope.outcome}`;
 40	  }
 41	
 42	  const result = envelope.result as PreflightResult;
 43	  const lines = [
 44	    `preflight: ${envelope.outcome}`,
 45	    `primary: ${result.providerMatrix.primary.available ? "ready" : "blocked"}`,
 46	    `secondary: ${result.providerMatrix.secondary.length}`,
 47	  ];
 48	
 49	  if (result.verificationGates) {
 50	    lines.push(`story gate: ${result.verificationGates.storyGate}`);
 51	    lines.push(`epic gate: ${result.verificationGates.epicGate}`);
 52	  }
 53	
 54	  return lines.join("\n");
 55	}
