154	async function writeProviderBinary(params: {
155	  dir: string;
156	  name: string;
157	  version: string;
158	  authStatus?: "authenticated" | "missing";
159	}) {
160	  const authStatus = params.authStatus ?? "authenticated";
161	  const scriptPath = join(params.dir, params.name);
162	  const script = [
163	    "#!/bin/sh",
164	    'if [ "$1" = "--version" ]; then',
165	    `  echo "${params.version}"`,
166	    "  exit 0",
167	    "fi",
168	    'if [ "$1" = "auth" ] && [ "$2" = "status" ]; then',
169	    authStatus === "authenticated" ? '  echo "authenticated"' : '  echo "missing" >&2',
170	    authStatus === "authenticated" ? "  exit 0" : "  exit 1",
171	    "fi",
172	    'echo "unexpected invocation" >&2',
173	    "exit 1",
174	    "",
175	  ].join("\n");
176	  await writeTextFile(scriptPath, script);
177	  await chmod(scriptPath, 0o755);
178	}
