 31	    params.authBehavior === "timeout"
 32	      ? "  sleep 2"
 33	      : params.authBehavior === "unknown"
 34	        ? '  echo "transient provider failure" >&2'
 35	        : authStatus === "authenticated"
 36	          ? '  echo "authenticated"'
