 30	function renderHumanSummary(envelope: OutputEnvelope) {
 31	  if (
 32	    typeof envelope.result !== "object" ||
 33	    envelope.result === null ||
 34	    !("techDesignShape" in envelope.result)
 35	  ) {
 36	    return `inspect: ${envelope.outcome}`;
 37	  }
 38	
 39	  const result = envelope.result as InspectResult;
 40	  const lines = [
 41	    `inspect: ${envelope.outcome}`,
 42	    `tech design: ${result.techDesignShape}`,
 43	    `stories: ${result.stories.length}`,
 44	    `impl insert: ${result.inserts.customStoryImplPromptInsert}`,
 45	    `verifier insert: ${result.inserts.customStoryVerifierPromptInsert}`,
 46	  ];
 47	
 48	  if (result.blockers.length > 0) {
 49	    lines.push(...result.blockers.map((blocker) => `blocker: ${blocker}`));
 50	  }
 51	
 52	  return lines.join("\n");
 53	}
 54	
 55	function emitOutput(params: {
 56	  envelope: OutputEnvelope;
 57	  json: boolean;
 58	}) {
 59	  if (params.json) {
 60	    console.log(JSON.stringify(params.envelope));
 61	    return;
 62	  }
 63	
 64	  console.log(renderHumanSummary(params.envelope));
 65	}
