 67	function inspectErrors(result: InspectResult): CliError[] {
 68	  if (result.status !== "blocked") {
 69	    return [];
 70	  }
 71	
 72	  if (
 73	    result.blockers.some((blocker) =>
 74	      blocker.startsWith("Unreadable prompt insert:")
 75	    )
 76	  ) {
 77	    return [
 78	      {
 79	        code: "PROMPT_INSERT_INVALID",
 80	        message: "Prompt insert inspection failed",
 81	      },
 82	    ];
 83	  }
 84	
 85	  return [
 86	    {
 87	      code: "INVALID_SPEC_PACK",
 88	      message: "Spec-pack inspection failed",
 89	    },
 90	  ];
 91	}
